    43→
    44→    /// <summary>
    45→    /// Handles <see cref="CreateCompanyCommand"/> by validating input, constructing the
    46→    /// Company aggregate root, persisting it through the repository, and committing via Unit-of-Work.
    47→    /// </summary>
    48→    internal sealed class CreateCompanyCommandHandler
    49→        : IRequestHandler<CreateCompanyCommand, CreateCompanyResult>
    50→    {
    51→        private readonly ICompanyRepository _companyRepository;
    52→        private readonly IUnitOfWork _unitOfWork;
    53→        private readonly ICurrencyConversionService _currencyConversion;
