    17→/// <summary>
    18→/// Command raised when a player attempts to file an Initial Public Offering (IPO)
    19→/// for one of his/her in-game companies.
    20→/// </summary>
    21→/// <param name="CompanyId">Aggregate identifier of the company that is filing the IPO.</param>
    22→/// <param name="Exchange">The exchange (e.g. “NYSE”, “NASDAQ”) where the company wants to list.</param>
    23→/// <param name="PricePerShare">Expected price per share in the game’s reference currency (USD).</param>
    24→/// <param name="SharesToIssue">Total number of shares the company will issue.</param>
    25→/// <param name="FilingDateUtc">The exact moment the filing is made. Must be in UTC.</param>
    26→public sealed record FileIPOCommand(
    27→    Guid CompanyId,
    28→    string Exchange,
    29→    decimal PricePerShare,
    30→    long SharesToIssue,
    31→    DateTime FilingDateUtc) : IRequest<Result<IPOResponse>>
    32→{
    33→    /// <summary>
    34→    /// Validation rules for <see cref="FileIPOCommand"/>.
    35→    /// </summary>
    36→    public sealed class Validator : AbstractValidator<FileIPOCommand>
    37→    {
    38→        public Validator(IDateTimeProvider clock)
    39→        {
    40→            RuleFor(x => x.CompanyId)
    41→                .NotEmpty();
    42→
    43→            RuleFor(x => x.Exchange)
    44→                .NotEmpty()
    45→                .MaximumLength(16)
    46→                .Must(exchange => exchange.Equals(exchange.ToUpper(CultureInfo.InvariantCulture)))
    47→                .WithMessage("Exchange must be in uppercase (e.g. \"NYSE\").");
    48→
    49→            RuleFor(x => x.PricePerShare)
    50→                .GreaterThan(0m)
    51→                .LessThanOrEqualTo(10_000m);
    52→
    53→            RuleFor(x => x.SharesToIssue)
    54→                .GreaterThan(0);
    55→
    56→            RuleFor(x => x.FilingDateUtc)
    57→                .Must(date => date.Kind == DateTimeKind.Utc)
    58→                .WithMessage("FilingDateUtc must be specified in UTC.")
    59→                .Must(date => date <= clock.UtcNow)
    60→                .WithMessage("Filing date cannot be set in the future.");
    61→        }
    62→    }
    63→
    64→    /// <summary>
    65→    /// Handles the <see cref="FileIPOCommand"/>.
    66→    /// </summary>
    67→    internal sealed class Handler : IRequestHandler<FileIPOCommand, Result<IPOResponse>>
    68→    {
    69→        private readonly ICompanyRepository          _companyRepository;
    70→        private readonly IUnitOfWork                 _unitOfWork;
    71→        private readonly IDateTimeProvider           _clock;
    72→        private readonly ILogger<Handler>            _logger;
    73→
    74→        public Handler(
    75→            ICompanyRepository companyRepository,
    76→            IUnitOfWork unitOfWork,
    77→            IDateTimeProvider clock,
    78→            ILogger<Handler> logger)
    79→        {
    80→            _companyRepository = companyRepository;
    81→            _unitOfWork        = unitOfWork;
    82→            _clock             = clock;
    83→            _logger            = logger;
    84→        }
    85→
    86→        public async Task<Result<IPOResponse>> Handle(
    87→            FileIPOCommand request,
    88→            CancellationToken cancellationToken)
    89→        {
    90→            // Acquire aggregate
    91→            Company? company =
    92→                await _companyRepository.GetAsync(request.CompanyId, cancellationToken);
    93→
    94→            if (company is null)
    95→            {
    96→                return Result<IPOResponse>.Failure($"Company '{request.CompanyId}' was not found.");
    97→            }
    98→
    99→            if (company.IsListed)
   100→            {
   101→                return Result<IPOResponse>.Failure(
   102→                    "The company is already publicly traded and therefore cannot file another IPO.");
   103→            }
   104→
   105→            // Domain operation — may throw domain-specific exceptions.
   106→            try
   107→            {
   108→                company.FileInitialPublicOffering(
   109→                    exchange:        request.Exchange,
   110→                    pricePerShare:   request.PricePerShare,
   111→                    sharesToIssue:   request.SharesToIssue,
   112→                    filingDateUtc:   request.FilingDateUtc);
   113→
   114→                _companyRepository.Update(company);
   115→
   116→                // Persist changes with optimistic concurrency.
   117→                await _unitOfWork.SaveChangesAsync(cancellationToken);
   118→
   119→                _logger.LogInformation(
   120→                    "IPO filed successfully for Company {CompanyId} on {Exchange}.",
   121→                    request.CompanyId,
   122→                    request.Exchange);
   123→
   124→                return Result<IPOResponse>.Success(new IPOResponse(
   125→                    company.Id,
   126→                    company.TickerSymbol,
   127→                    request.Exchange,
   128→                    request.PricePerShare,
   129→                    request.SharesToIssue,
   130→                    request.FilingDateUtc));
   131→            }
   132→            catch (ConcurrencyException ex)
   133→            {
   134→                _logger.LogWarning(
   135→                    ex,
   136→                    "Concurrency conflict while filing IPO for Company {CompanyId}.",
   137→                    request.CompanyId);
   138→
   139→                return Result<IPOResponse>.Failure(
   140→                    "IPO filing failed due to a concurrency conflict. Please try again.");
   141→            }
   142→            catch (DomainValidationException ex)
   143→            {
   144→                _logger.LogDebug(
   145→                    ex,
   146→                    "Domain validation error while filing IPO for Company {CompanyId}.",
   147→                    request.CompanyId);
   148→
   149→                return Result<IPOResponse>.Failure(ex.Message);
   150→            }
   151→            catch (Exception ex)
   152→            {
   153→                _logger.LogError(
   154→                    ex,
   155→                    "Unexpected error while filing IPO for Company {CompanyId}.",
   156→                    request.CompanyId);
   157→
   158→                return Result<IPOResponse>.Failure(
   159→                    "An unexpected error occurred while filing the IPO.");
   160→            }
   161→        }
   162→    }
   163→}
