    69→            _logger.LogDebug("Database transaction started ({TransactionId}).", _currentTransaction.TransactionId);
    70→        }
    71→
    72→        /// <inheritdoc />
    73→        public async Task CommitAsync(CancellationToken cancellationToken = default)
    74→        {
    75→            ThrowIfDisposed();
    76→
    77→            if (_currentTransaction is null)
    78→            {
    79→                _logger.LogWarning("Commit requested without an active transaction. Operation ignored.");
    80→                return;
    81→            }
    82→
    83→            try
    84→            {
    85→                await SaveChangesInternalAsync(cancellationToken).ConfigureAwait(false);
    86→
    87→                await _currentTransaction
    88→                    .CommitAsync(cancellationToken)
    89→                    .ConfigureAwait(false);
    90→
    91→                _logger.LogDebug("Transaction committed ({TransactionId}).", _currentTransaction.TransactionId);
    92→            }
    93→            catch (Exception ex)
    94→            {
    95→                _logger.LogError(ex, "Commit failed. Rolling back transaction ({TransactionId}).",
    96→                                 _currentTransaction.TransactionId);
    97→
    98→                await RollbackAsync(cancellationToken).ConfigureAwait(false);
    99→                throw;
   100→            }
   101→            finally
   102→            {
   103→                await DisposeCurrentTransactionAsync().ConfigureAwait(false);
   104→            }
   105→        }
   106→
   107→        /// <inheritdoc />
   108→        public async Task RollbackAsync(CancellationToken cancellationToken = default)
   109→        {
   110→            ThrowIfDisposed();
   111→
   112→            if (_currentTransaction is null)
   113→            {
   114→                _logger.LogWarning("Rollback requested without an active transaction. Operation ignored.");
   115→                return;
   116→            }
   117→
   118→            try
   119→            {
   120→                await _currentTransaction
   121→                    .RollbackAsync(cancellationToken)
   122→                    .ConfigureAwait(false);
   123→
   124→                _logger.LogInformation("Transaction rolled back ({TransactionId}).",
   125→                                       _currentTransaction.TransactionId);
   126→            }
   127→            finally
   128→            {
   129→                await DisposeCurrentTransactionAsync().ConfigureAwait(false);
   130→            }
   131→        }
   132→
   133→        #endregion
   134→
   135→        #region Persistence
   136→
   137→        /// <inheritdoc />
   138→        public async Task<int> SaveChangesAsync(CancellationToken cancellationToken = default)
   139→        {
   140→            ThrowIfDisposed();
   141→
   142→            if (_currentTransaction is null)
   143→            {
   144→                // No explicit transaction ongoing; save immediately.
   145→                return await SaveChangesInternalAsync(cancellationToken).ConfigureAwait(false);
   146→            }
   147→
   148→            // Inside explicit transaction; defer to Commit.
   149→            return 0;
   150→        }
   151→
   152→        private async Task<int> SaveChangesInternalAsync(CancellationToken cancellationToken)
   153→        {
   154→            try
   155→            {
   156→                var rows = await _context
   157→                                 .SaveChangesAsync(cancellationToken)
   158→                                 .ConfigureAwait(false);
   159→
   160→                _logger.LogTrace("EF Core saved {RowCount} changes.", rows);
   161→
   162→                return rows;
   163→            }
   164→            catch (DbUpdateConcurrencyException ex)
   165→            {
   166→                _logger.LogWarning(ex,
   167→                                   "Concurrency conflict detected during SaveChanges. "
   168→                                   + "Exception will be re-thrown to the caller.");
   169→                throw;
   170→            }
   171→            catch (DbUpdateException ex)
   172→            {
   173→                _logger.LogError(ex, "Database update exception encountered.");
   174→                throw;
   175→            }
   176→        }
   177→
   178→        #endregion
   179→
   180→        #region IDisposable / IAsyncDisposable
   181→
   182→        private async Task DisposeCurrentTransactionAsync()
   183→        {
   184→            if (_currentTransaction is null) return;
   185→
   186→            await _currentTransaction.DisposeAsync().ConfigureAwait(false);
   187→            _currentTransaction = null;
   188→        }
   189→
   190→        private void ThrowIfDisposed()
   191→        {
   192→            if (_disposed)
   193→                throw new ObjectDisposedException(nameof(UnitOfWork),
   194→                                                  "Attempted to use UnitOfWork after it has been disposed.");
   195→        }
   196→
   197→        public async ValueTask DisposeAsync()
   198→        {
   199→            if (_disposed) return;
   200→
   201→            _disposed = true;
   202→
   203→            try
   204→            {
   205→                await DisposeCurrentTransactionAsync().ConfigureAwait(false);
   206→            }
   207→            catch (Exception ex)
   208→            {
   209→                _logger.LogError(ex, "Error disposing current transaction.");
   210→            }
   211→
   212→            await _context.DisposeAsync().ConfigureAwait(false);
   213→
   214→            _logger.LogDebug("UnitOfWork disposed.");
   215→        }
   216→
   217→        #endregion
   218→    }
