   152→        /// <exception cref="InvalidOperationException">
   153→        /// Thrown when balance is insufficient or limit exceeded.
   154→        /// </exception>
   155→        public void DebitWallet(decimal amount, string reason, IClock clock)
   156→        {
   157→            if (amount <= 0)
   158→                throw new ArgumentOutOfRangeException(nameof(amount), amount, "Amount must be positive.");
   159→
   160→            lock (_sync)
   161→            {
   162→                var today = clock.UtcNow.Date;
   163→                var debitedToday = _dailyDebits.TryGetValue(today, out var total) ? total : 0m;
