#### OfflineQueuingStrategy.cs
```csharp
namespace TycoonVerse.Infrastructure.Sync;

/// <summary>
/// Strategy that queues player actions locally for batch synchronization.
/// This is the default behavior for standard game modes, implementing the
/// offline-first approach documented in ADR-003.
/// </summary>
internal sealed class OfflineQueuingStrategy : IActionSyncStrategy
{
    private readonly IPlayerActionRepository _actionRepository;
    private readonly ILogger<OfflineQueuingStrategy> _logger;

    public bool RequiresConnectivity => false;

    public OfflineQueuingStrategy(
        IPlayerActionRepository actionRepository,
        ILogger<OfflineQueuingStrategy> logger)
    {
        _actionRepository = actionRepository;
        _logger = logger;
    }

    public async Task<ActionSyncResult> SyncAsync(
        PlayerAction action,
        CancellationToken cancellationToken)
    {
        // Existing behavior: persist locally for batch sync
        await _actionRepository.AddAsync(action, cancellationToken);

        _logger.LogDebug(
            "Action {ActionId} queued for offline sync",
            action.Id);

        return new ActionSyncResult(
            IsSuccess: true,
            WasQueued: true);
    }
}
```

#### RealTimeSyncStrategy.cs
```csharp
namespace TycoonVerse.Infrastructure.Sync;

/// <summary>
/// Strategy that immediately synchronizes player actions with the server.
/// Used for Hardcore Mode where server confirmation is required before
/// proceeding with the action.
/// </summary>
internal sealed class RealTimeSyncStrategy : IActionSyncStrategy
{
    private readonly IApiClient _apiClient;
    private readonly IConnectivityService _connectivity;
    private readonly ILogger<RealTimeSyncStrategy> _logger;

    public bool RequiresConnectivity => true;

    public RealTimeSyncStrategy(
        IApiClient apiClient,
        IConnectivityService connectivity,
        ILogger<RealTimeSyncStrategy> logger)
    {
        _apiClient = apiClient;
        _connectivity = connectivity;
        _logger = logger;
    }

    public async Task<ActionSyncResult> SyncAsync(
        PlayerAction action,
        CancellationToken cancellationToken)
    {
        // Check connectivity first
        if (!_connectivity.IsOnline)
        {
            return new ActionSyncResult(
                IsSuccess: false,
                WasQueued: false,
                FailureReason: "Network connectivity required for Hardcore Mode");
        }

        try
        {
            var request = new ApiRequest(
                endpoint: new Uri("/api/v1/actions/immediate", UriKind.Relative),
                method: HttpMethod.Post,
                body: action);

            var response = await _apiClient.SendAsync<ImmediateSyncResponse>(
                request,
                cancellationToken);

            if (response?.IsConfirmed == true)
            {
                _logger.LogInformation(
                    "Action {ActionId} confirmed by server in real-time",
                    action.Id);

                return new ActionSyncResult(
                    IsSuccess: true,
                    WasQueued: false,
                    ServerConfirmationId: response.ConfirmationId);
            }

            return new ActionSyncResult(
                IsSuccess: false,
                WasQueued: false,
                FailureReason: response?.RejectionReason ?? "Server rejected action");
        }
        catch (ApiException ex)
        {
            _logger.LogWarning(ex,
                "Real-time sync failed for action {ActionId}",
                action.Id);

            return new ActionSyncResult(
                IsSuccess: false,
                WasQueued: false,
                FailureReason: $"Server error: {ex.StatusCode}");
        }
    }
}
```

#### ActionSyncStrategyFactory.cs
```csharp
namespace TycoonVerse.Infrastructure.Sync;

/// <summary>
/// Factory that resolves the correct sync strategy based on player context.
/// Registered as a singleton in the DI container.
/// </summary>
internal sealed class ActionSyncStrategyFactory : IActionSyncStrategyFactory
{
    private readonly IPlayerRepository _playerRepository;
    private readonly OfflineQueuingStrategy _offlineStrategy;
    private readonly RealTimeSyncStrategy _realTimeStrategy;

    public ActionSyncStrategyFactory(
        IPlayerRepository playerRepository,
        OfflineQueuingStrategy offlineStrategy,
        RealTimeSyncStrategy realTimeStrategy)
    {
        _playerRepository = playerRepository;
        _offlineStrategy = offlineStrategy;
        _realTimeStrategy = realTimeStrategy;
    }

    public IActionSyncStrategy GetStrategy(Guid playerId)
    {
        // Could be async in real implementation with caching
        var player = _playerRepository.GetByIdAsync(playerId, CancellationToken.None)
            .GetAwaiter().GetResult();

        return GetStrategy(player?.GameMode ?? GameMode.Standard);
    }

    public IActionSyncStrategy GetStrategy(GameMode mode)
    {
        return mode switch
        {
            GameMode.Hardcore => _realTimeStrategy,
            GameMode.Standard => _offlineStrategy,
            GameMode.Tutorial => _offlineStrategy,
            _ => _offlineStrategy
        };
    }
}
```

