        ICompanyRepository companyRepository,
        IUnitOfWork unitOfWork,
        ICurrencyConversionService currencyConversion,
        IActionSyncStrategyFactory syncStrategyFactory, // NEW
        ILogger<CreateCompanyCommandHandler> logger)
    {
        _companyRepository = companyRepository;
        _unitOfWork = unitOfWork;
        _currencyConversion = currencyConversion;
        _syncStrategyFactory = syncStrategyFactory; // NEW
        _logger = logger;
    }

    public async Task<CreateCompanyResult> Handle(
        CreateCompanyCommand request,
        CancellationToken cancellationToken)
    {
        // ... existing validation logic (lines 72-97) ...

        // Create the domain entity
        var company = Company.Create(/* ... */);

        // Persist locally
        await _companyRepository.AddAsync(company, cancellationToken);
        await _unitOfWork.SaveChangesAsync(cancellationToken);

        // NEW: Sync according to player's game mode
        var strategy = _syncStrategyFactory.GetStrategy(request.RequestedByPlayerId);
        var action = PlayerAction.FromCommand(request, company.Id);
        var syncResult = await strategy.SyncAsync(action, cancellationToken);

        if (!syncResult.IsSuccess && strategy.RequiresConnectivity)
        {
            // Rollback for Hardcore mode if sync fails
            // This is where the real-time requirement is enforced
            throw new SyncRequiredException(syncResult.FailureReason);
        }

        _logger.LogInformation(
            "Player {PlayerId} created company {CompanyName} (Synced: {WasSynced})",
            request.RequestedByPlayerId,
            company.Name,
            !syncResult.WasQueued);

        return new CreateCompanyResult(company.Id, company.CreatedAtUtc);
